class Solution {
    public boolean canPartitionKSubsets(int[] nums, int k) {
        int sum = 0;
        for (int num : nums) {
            sum += num;
        }
        if (sum % k != 0) {
            return false;
        }
        int target = sum / k;
        boolean[] dp = new boolean[1 << nums.length];
        dp[0] = true;
        int[] sums = new int[1 << nums.length];
        for (int i = 0; i < (1 << nums.length); i++) {
            if (!dp[i]) {
                continue;
            }
            for (int j = 0; j < nums.length; j++) {
                if (((i >> j) & 1) == 0) {
                    int next = i | (1 << j);
                    if (sums[i] + nums[j] <= target) {
                        sums[next] = sums[i] + nums[j];
                        dp[next] = true;
                    }
                    if (sums[i] + nums[j] == target) {
                        sums[next] = 0;
                    }
                }
            }
        }
        return dp[(1 << nums.length) - 1];
    }
}
